import mongoose from 'mongoose'
import bcrypt from 'bcryptjs'

import * as dotenv from 'dotenv'
import * as path from 'path'
dotenv.config({ path: path.resolve(__dirname, '../../.env') })

const MONGODB_URI = process.env.MONGODB_URI || 'mongodb://localhost:27017/examprep'

async function connectDB() {
  await mongoose.connect(MONGODB_URI)
  console.log('Connected to MongoDB')
}

// ─── Schemas ────────────────────────────────────────────────────────────────

const UserSchema = new mongoose.Schema({
  name: String, email: { type: String, unique: true }, password: String,
  role: { type: String, default: 'student' }, isActive: { type: Boolean, default: true },
  isPaid: { type: Boolean, default: false },
})
const SubjectSchema = new mongoose.Schema({ name: String, code: String, description: String })
const QuestionSchema = new mongoose.Schema({
  question: String, type: { type: String, default: 'MCQ' },
  optionA: String, optionB: String, optionC: String, optionD: String,
  correctAnswer: String, difficulty: { type: String, default: 'MEDIUM' },
  subject: mongoose.Schema.Types.ObjectId, topic: String,
})
const ExamSchema = new mongoose.Schema({
  title: String, subject: mongoose.Schema.Types.ObjectId,
  questions: [mongoose.Schema.Types.ObjectId],
  timeLimit: { type: Number, default: 120 },
  passingMark: { type: Number, default: 50 },
  type: { type: String, default: 'MOCK' },
  isActive: { type: Boolean, default: true },
  description: String,
}, { timestamps: true })

const User = mongoose.models.User || mongoose.model('User', UserSchema)
const Subject = mongoose.models.Subject || mongoose.model('Subject', SubjectSchema)
const Question = mongoose.models.Question || mongoose.model('Question', QuestionSchema)
const Exam = mongoose.models.Exam || mongoose.model('Exam', ExamSchema)

