// ─── Seed Function ───────────────────────────────────────────────────────────

async function seed() {
  await connectDB()

  // Clear existing data
  await Promise.all([
    User.deleteMany({}),
    Subject.deleteMany({}),
    Question.deleteMany({}),
    Exam.deleteMany({}),
  ])
  console.log('Cleared existing data')

  // Create users
  const adminPass = await bcrypt.hash('admin123', 10)
  const studentPass = await bcrypt.hash('student123', 10)
  await User.create([
    { name: 'Admin', email: 'admin@example.com', password: adminPass, role: 'admin' },
    { name: 'Student', email: 'student@example.com', password: studentPass, role: 'student' },
  ])
  console.log('Created users')

  // Create subject
  const subject = await Subject.create({
    name: 'Information Science',
    code: 'IS',
    description: 'BSc Information Science Exit Exam',
  })
  console.log('Created subject')

  // Helper to create questions and exam
  async function createModelExam(
    modelNum: number,
    qs: Q[],
    description: string
  ) {
    const questionDocs = await Question.insertMany(
      qs.map(([question, optionA, optionB, optionC, optionD, correctAnswer, difficulty, topic]) => ({
        question, optionA, optionB, optionC, optionD,
        correctAnswer, difficulty, topic,
        subject: subject._id, type: 'MCQ',
      }))
    )
    const exam = await Exam.create({
      title: `BSc Information Science — Model Exam ${modelNum}`,
      subject: subject._id,
      questions: questionDocs.map((q: any) => q._id),
      timeLimit: 120,
      passingMark: 50,
      type: 'MOCK',
      isActive: true,
      description,
    })
    console.log(`Created Model Exam ${modelNum} with ${questionDocs.length} questions (ID: ${exam._id})`)
    return exam
  }

  await createModelExam(1, MODEL1_QS, 'Data Structures, Algorithms & Information Science Fundamentals')
  await createModelExam(2, MODEL2_QS, 'Library Science, Digital Libraries & Information Retrieval')
  await createModelExam(3, MODEL3_QS, 'Programming, Visual Basic & Web Development')
  await createModelExam(4, MODEL4_QS, 'Database Systems, Networking, Knowledge Management & Scholarly Communication')

  console.log('\n✅ Seed complete!')
  console.log('Admin:   admin@example.com / admin123')
  console.log('Student: student@example.com / student123')
  await mongoose.disconnect()
}

seed().catch(err => { console.error(err); process.exit(1) })
